import type { Metadata } from "next";
import LabResultsReport from "./LabResultsReport";

export const metadata: Metadata = {
  title: "臨床検査レポート / 検査結果確認 | ぐんじょう 電子カルテ",
  description:
    "入院患者の臨床検査レポート。患者・検体コンテキスト（患者ID / 氏名・年齢・性別 / 病棟 / 検体採取日時 / 報告日時 / オーダー番号）の上で、検査区分（血液一般 / 生化学 / 凝固 / 免疫・血清 / 尿一般）ごとに 結果値を基準値と照合し、H(高値) / L(低値) / HH・LL(異常) / パニック値 を アイコン＋コード＋トーン で判定。異常値のみフィルタ、前回値との推移（Delta）、項目別トレンドチャート（基準線つき）を表示。パニック値は即時の医師報告（報告記録）が必要で、報告するまで結果確認（サインオフ）をブロックします。",
};

export default function LabResultsPage() {
  return <LabResultsReport />;
}

// ── HAND-ROLLED (FINDINGS-55, 🟠) ─────────────────────────────────────────────
// The reference-range / abnormal-value flag. @gunjo/ui ships no
// `ReferenceValue` / `AbnormalFlag` / `RangeIndicator` primitive, so this is
// built from `Badge` (tone) + tabler icons (shape, NOT colour-only) + sr-only
// text. Same gap as the #54 vitals screen. Ideal library API:
//   <AbnormalFlag value={..} refLow={..} refHigh={..} panicLow/High criticalLow/High unit />
// deriving flag + tone + accessible text via a pure `flagValue()` helper.
import * as React from "react";
import {
  IconChevronUp,
  IconChevronsUp,
  IconChevronDown,
  IconChevronsDown,
  IconAlertTriangleFilled,
  IconCheck,
} from "@tabler/icons-react";
import { Badge } from "@gunjo/ui";
import type { FlagResult, AnalyteFlag } from "./lab-data";

const FLAG_ICON: Record<AnalyteFlag, React.ComponentType<{ className?: string }>> = {
  normal: IconCheck,
  H: IconChevronUp,
  L: IconChevronDown,
  HH: IconChevronsUp,
  LL: IconChevronsDown,
  panicH: IconAlertTriangleFilled,
  panicL: IconAlertTriangleFilled,
};

// label rides on icon + code + tone — never colour alone.
const FLAG_LABEL: Record<AnalyteFlag, string> = {
  normal: "正常",
  H: "H 高値",
  L: "L 低値",
  HH: "HH 異常高値",
  LL: "LL 異常低値",
  panicH: "パニック値↑",
  panicL: "パニック値↓",
};

const TONE_TO_VARIANT: Record<
  FlagResult["tone"],
  "success" | "warning" | "destructive"
> = {
  success: "success",
  warning: "warning",
  destructive: "destructive",
};

export function AbnormalFlag({ result }: { result: FlagResult }) {
  const Glyph = FLAG_ICON[result.flag];
  return (
    <Badge
      variant={TONE_TO_VARIANT[result.tone]}
      className="gap-1 px-2"
      // panic gets a heavier ring so it is distinct beyond hue
      data-panic={result.panic ? "" : undefined}
    >
      <Glyph className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
      <span aria-hidden="true">{FLAG_LABEL[result.flag]}</span>
      <span className="sr-only">{result.srText}</span>
    </Badge>
  );
}

"use client";

// 推移 (trend) for a selected analyte.
// Uses @gunjo/ui <LineChart>. LineChart supports a single `referenceValue`
// horizontal line but NO shaded `referenceBand` (FINDINGS-55 🟠), so a
// reference RANGE (low–high) can't be drawn as a band — we draw the high bound
// as the reference line and state the full range in the accessible table.
import * as React from "react";
import { LineChart, Badge } from "@gunjo/ui";
import {
  type Analyte,
  flagValue,
  formatAnalyte,
  refRangeText,
} from "./lab-data";
import { AbnormalFlag } from "./AbnormalFlag";

export function AnalyteTrend({ analyte }: { analyte: Analyte }) {
  const points = React.useMemo(() => {
    const hist = analyte.history.map((h) => ({ label: h.date, value: h.value }));
    if (analyte.value != null) hist.push({ label: "今回", value: analyte.value });
    return hist;
  }, [analyte]);

  const result = flagValue(analyte);
  // reference line: high bound if present, otherwise low bound.
  const refValue = analyte.refHigh ?? analyte.refLow ?? undefined;
  const refLabel =
    analyte.refHigh != null
      ? `基準上限 ${formatAnalyte(analyte.refHigh, analyte.digits)}`
      : analyte.refLow != null
        ? `基準下限 ${formatAnalyte(analyte.refLow, analyte.digits)}`
        : "基準値";

  return (
    <div>
      <div className="mb-3 flex flex-wrap items-baseline gap-x-3 gap-y-1">
        <span className="text-base font-semibold">
          {analyte.name}
          <span className="ml-1 text-xs font-normal text-muted-foreground">
            {analyte.nameJa}
          </span>
        </span>
        <span className="text-sm tabular-nums">
          今回 {analyte.value != null ? formatAnalyte(analyte.value, analyte.digits) : "—"}
          <span className="text-muted-foreground"> {analyte.unit}</span>
        </span>
        <AbnormalFlag result={result} />
        <span className="text-xs text-muted-foreground">
          基準値 {refRangeText(analyte)}
        </span>
      </div>

      <LineChart
        className="h-[180px] w-full"
        showDots
        series={[{ label: `${analyte.name} 推移`, data: points, color: "info" }]}
        referenceValue={refValue}
        referenceLabel={refLabel}
        formatValue={(v) => `${formatAnalyte(v, analyte.digits)}${analyte.unit ? " " + analyte.unit : ""}`}
        aria-label={`${analyte.name}（${analyte.nameJa}）の推移。基準値 ${refRangeText(analyte)}。`}
      />

      {/* Accessible text/table alternative for the SVG chart (chart is role=img). */}
      <details className="mt-3">
        <summary className="cursor-pointer text-xs font-medium text-muted-foreground">
          推移データ（表で表示）
        </summary>
        <table className="mt-2 w-full text-sm">
          <caption className="sr-only">
            {analyte.name} の測定推移。基準値 {refRangeText(analyte)}。
          </caption>
          <thead>
            <tr className="border-b text-xs text-muted-foreground">
              <th scope="col" className="py-1 text-left font-medium">
                測定日
              </th>
              <th scope="col" className="py-1 text-right font-medium">
                結果値
              </th>
            </tr>
          </thead>
          <tbody>
            {points.map((p) => (
              <tr key={String(p.label)} className="border-b last:border-0">
                <th scope="row" className="py-1 text-left font-normal">
                  {String(p.label)}
                </th>
                <td className="py-1 text-right tabular-nums">
                  {formatAnalyte(p.value, analyte.digits)} {analyte.unit}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </details>
      <p className="mt-2 text-xs text-muted-foreground">
        <Badge variant="outline" className="mr-1 align-middle">
          基準線
        </Badge>
        {refLabel}（{analyte.unit || "比"}）。基準範囲の帯表示はライブラリ未対応のため上限線で代用。
      </p>
    </div>
  );
}

// 検査結果 / clinical-lab domain model + the reference-range flag engine.
//
// NOTE (FINDINGS-55): @gunjo/ui has no "value vs reference range → flag"
// primitive, so the whole flag engine below is hand-rolled. It is the same gap
// the #54 vitals screen hit. The pure `flagValue()` helper + the `AbnormalFlag`
// presentational component (AbnormalFlag.tsx) are what an ideal
// `ReferenceValue` / `flagValue()` primitive in the library would ship.

export type AnalyteFlag =
  | "normal" // 正常 — within reference range
  | "H" // 高値 — above reference high
  | "L" // 低値 — below reference low
  | "HH" // 異常高値 — far above (critical-high gate)
  | "LL" // 異常低値 — far below (critical-low gate)
  | "panicH" // パニック値（高）— life-threatening high
  | "panicL"; // パニック値（低）— life-threatening low

export type AnalyteGroupId =
  | "hematology" // 血液一般
  | "biochemistry" // 生化学
  | "coagulation" // 凝固
  | "immunology" // 免疫・血清
  | "urinalysis"; // 尿一般

export interface AnalyteGroupMeta {
  id: AnalyteGroupId;
  label: string; // 血液一般 etc.
  short: string;
}

export const ANALYTE_GROUPS: AnalyteGroupMeta[] = [
  { id: "hematology", label: "血液一般", short: "血算" },
  { id: "biochemistry", label: "生化学", short: "生化" },
  { id: "coagulation", label: "凝固", short: "凝固" },
  { id: "immunology", label: "免疫・血清", short: "免疫" },
  { id: "urinalysis", label: "尿一般", short: "尿" },
];

export interface Analyte {
  id: string;
  group: AnalyteGroupId;
  /** 項目名 e.g. WBC */
  name: string;
  /** 和名 e.g. 白血球数 */
  nameJa: string;
  unit: string;
  /** 基準値（正常範囲）下限。null = 上限のみ運用（例: CRP）。 */
  refLow: number | null;
  refHigh: number | null;
  /** パニック下限/上限 — これを超える/下回ると即時報告対象。 */
  panicLow?: number;
  panicHigh?: number;
  /**
   * 異常域 (HH / LL) ゲート。基準を外れた上でこの閾値を越えると HH/LL。
   * 省略時は基準外＝H/L のみ。
   */
  criticalLow?: number;
  criticalHigh?: number;
  /** 今回値。null = 測定不能/未報告。 */
  value: number | null;
  /** 過去→直近 の履歴（推移用）。末尾の手前が「前回値」。 */
  history: { date: string; value: number }[];
  /** 表示小数桁。 */
  digits?: number;
}

export interface FlagResult {
  flag: AnalyteFlag;
  /** true なら基準外（フィルタ対象）。 */
  abnormal: boolean;
  /** true ならパニック値（sign-off ブロック対象）。 */
  panic: boolean;
  /** 表示コード H / L / HH / LL / 正常。 */
  code: string;
  /** スクリーンリーダー向け完全文。 */
  srText: string;
  /** semantic tone — success / warning / destructive. */
  tone: "success" | "warning" | "destructive";
}

/**
 * PURE flag engine — value + reference range → flag + tone + accessible text.
 * This is the function an ideal @gunjo/ui `flagValue()` would expose.
 */
export function flagValue(a: Analyte): FlagResult {
  if (a.value == null) {
    return {
      flag: "normal",
      abnormal: false,
      panic: false,
      code: "—",
      srText: `${a.name} 測定値なし`,
      tone: "success",
    };
  }
  const v = a.value;
  const fmtV = formatAnalyte(v, a.digits);

  // パニック値（最優先・生命に関わる）
  if (a.panicHigh != null && v >= a.panicHigh) {
    return panic("panicH", "パニック値", "高");
  }
  if (a.panicLow != null && v <= a.panicLow) {
    return panic("panicL", "パニック値", "低");
  }

  const aboveHigh = a.refHigh != null && v > a.refHigh;
  const belowLow = a.refLow != null && v < a.refLow;

  if (aboveHigh) {
    const critical = a.criticalHigh != null && v >= a.criticalHigh;
    return out(critical ? "HH" : "H", critical ? "異常高値" : "高値", "warning");
  }
  if (belowLow) {
    const critical = a.criticalLow != null && v <= a.criticalLow;
    return out(critical ? "LL" : "L", critical ? "異常低値" : "低値", "warning");
  }

  return {
    flag: "normal",
    abnormal: false,
    panic: false,
    code: "正常",
    srText: `${a.name} ${fmtV}${a.unit} 正常範囲内`,
    tone: "success",
  };

  function panic(
    flag: AnalyteFlag,
    word: string,
    dir: string
  ): FlagResult {
    return {
      flag,
      abnormal: true,
      panic: true,
      code: "パニック",
      srText: `${a.name} ${fmtV}${a.unit} ${word}（${dir}）即時報告対象`,
      tone: "destructive",
    };
  }
  function out(
    code: string,
    word: string,
    tone: "warning"
  ): FlagResult {
    const isCritical = code === "HH" || code === "LL";
    return {
      flag: code as AnalyteFlag,
      abnormal: true,
      panic: false,
      code,
      srText: `${a.name} ${fmtV}${a.unit} ${word}（基準値 ${refRangeText(a)}）`,
      tone: isCritical ? "destructive" : tone,
    };
  }
}

export function formatAnalyte(v: number, digits = 0): string {
  return v.toLocaleString("ja-JP", {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits,
  });
}

export function refRangeText(a: Analyte): string {
  const lo = a.refLow != null ? formatAnalyte(a.refLow, a.digits) : null;
  const hi = a.refHigh != null ? formatAnalyte(a.refHigh, a.digits) : null;
  if (lo != null && hi != null) return `${lo}–${hi} ${a.unit}`;
  if (hi != null) return `≤ ${hi} ${a.unit}`;
  if (lo != null) return `≥ ${lo} ${a.unit}`;
  return "—";
}

/** 前回値（履歴の最後）。 */
export function previousValue(a: Analyte): number | null {
  if (a.history.length === 0) return null;
  return a.history[a.history.length - 1].value;
}

/** 推移（前回→今回の差）。null safe。 */
export function deltaFromPrevious(a: Analyte): number | null {
  const prev = previousValue(a);
  if (prev == null || a.value == null) return null;
  return a.value - prev;
}

