"use client";

import * as React from "react";
import {
  Container,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Alert,
  AlertTitle,
  AlertDescription,
  Badge,
  Button,
  Statistic,
  Delta,
  Select,
  Switch,
  Table,
  TableHeader,
  TableBody,
  TableHead,
  TableRow,
  TableCell,
  EmptyState,
  cn,
} from "@gunjo/ui";
import {
  IconAlertTriangleFilled,
  IconCheck,
  IconPrinter,
  IconRefresh,
  IconChevronDown,
  IconStethoscope,
} from "@tabler/icons-react";
import {
  ANALYTES,
  ANALYTE_GROUPS,
  flagValue,
  formatAnalyte,
  refRangeText,
  deltaFromPrevious,
  previousValue,
  type Analyte,
  type AnalyteGroupId,
  type FlagResult,
} from "./lab-data";
import { AbnormalFlag } from "./AbnormalFlag";
import { AnalyteTrend } from "./AnalyteTrend";

const NOW = "2026-06-23 09:50";

// Precompute flags once.
type Row = { analyte: Analyte; flag: FlagResult };
const ALL_ROWS: Row[] = ANALYTES.map((a) => ({ analyte: a, flag: flagValue(a) }));

export default function LabResultsReport() {
  const [abnormalOnly, setAbnormalOnly] = React.useState(false);
  const [groupFilter, setGroupFilter] = React.useState<AnalyteGroupId | "all">("all");
  const [selectedTrend, setSelectedTrend] = React.useState<string>("k");
  const [ackedPanics, setAckedPanics] = React.useState<Set<string>>(new Set());
  const [signedOff, setSignedOff] = React.useState(false);

  const panicRows = ALL_ROWS.filter((r) => r.flag.panic);
  const abnormalCount = ALL_ROWS.filter((r) => r.flag.abnormal).length;
  const panicCount = panicRows.length;
  const unackedPanics = panicRows.filter((r) => !ackedPanics.has(r.analyte.id));
  const allPanicsAcked = unackedPanics.length === 0;

  const visibleRows = React.useMemo(() => {
    return ALL_ROWS.filter((r) => {
      if (groupFilter !== "all" && r.analyte.group !== groupFilter) return false;
      if (abnormalOnly && !r.flag.abnormal) return false;
      return true;
    });
  }, [abnormalOnly, groupFilter]);

  const rowsByGroup = React.useMemo(() => {
    const map = new Map<AnalyteGroupId, Row[]>();
    for (const r of visibleRows) {
      const arr = map.get(r.analyte.group) ?? [];
      arr.push(r);
      map.set(r.analyte.group, arr);
    }
    return map;
  }, [visibleRows]);

  const trendAnalyte =
    ANALYTES.find((a) => a.id === selectedTrend) ?? ANALYTES[0];

  function ackPanic(id: string) {
    setAckedPanics((prev) => {
      const next = new Set(prev);
      next.add(id);
      return next;
    });
  }
  function ackAllPanics() {
    setAckedPanics(new Set(panicRows.map((r) => r.analyte.id)));
  }

  return (
    <main className="min-h-screen bg-muted/20 py-6">
      <Container size="2xl" className="space-y-6">
        {/* ───────────────────────── Page heading ───────────────────────── */}
        <header className="space-y-1">
          <div className="flex flex-wrap items-center gap-2">
            <h1 className="text-2xl font-bold tracking-tight">臨床検査レポート</h1>
            <Badge variant="outline">検査結果確認</Badge>
            {signedOff ? (
              <Badge variant="success" className="gap-1">
                <IconCheck className="h-3.5 w-3.5" aria-hidden="true" />
                確認済み
              </Badge>
            ) : (
              <Badge variant="warning">未確認</Badge>
            )}
          </div>
          <p className="text-sm text-muted-foreground">
            結果値を基準値と照合し、H/L・パニック値を判定。区分ごとに推移を確認し、パニック値は医師報告のうえ結果確認（サインオフ）します。
          </p>
        </header>

        {/* ──────────────── Patient / specimen context ──────────────── */}
        <Card>
          <CardContent className="p-4">
            <dl className="grid grid-cols-2 gap-x-4 gap-y-3 sm:grid-cols-3 lg:grid-cols-6">
              <ContextField label="患者ID" value={PATIENT_FIELDS.id} mono />
              <ContextField label="氏名 / 年齢・性別" value={PATIENT_FIELDS.name} />
              <ContextField label="病棟・病室" value={PATIENT_FIELDS.ward} />
              <ContextField label="検体採取日時" value={PATIENT_FIELDS.collectedAt} />
              <ContextField label="報告日時" value={PATIENT_FIELDS.reportedAt} />
              <ContextField label="オーダー番号 / 検査種別" value={PATIENT_FIELDS.order} mono />
            </dl>
          </CardContent>
        </Card>

        {/* ──────────────── PANIC VALUE alert (assertive, acknowledgeable) ──────────────── */}
        {/* HAND-ROLLED on @gunjo/ui <Alert>: Alert has no acknowledge action or
            aria-live; we add role/aria-live=assertive + an ack workflow (FINDINGS-55 🟠). */}
        {panicCount > 0 && (
          <section aria-labelledby="panic-heading">
            <Alert
              variant="destructive"
              aria-live="assertive"
              className="border-2"
            >
              <IconAlertTriangleFilled aria-hidden="true" />
              <AlertTitle as="h2" id="panic-heading" className="text-base">
                パニック値 {panicCount} 件 — 即時の医師報告が必要です
              </AlertTitle>
              <AlertDescription>
                <p className="mb-2">
                  生命に関わる危険域の結果です。報告（確認）するまで結果確認（サインオフ）はできません。
                </p>
                <ul className="space-y-2">
                  {panicRows.map((r) => {
                    const acked = ackedPanics.has(r.analyte.id);
                    return (
                      <li
                        key={r.analyte.id}
                        className="flex flex-wrap items-center gap-2 rounded-md border border-destructive-border bg-background/60 px-3 py-2"
                      >
                        <span className="font-semibold">{r.analyte.name}</span>
                        <span className="tabular-nums">
                          {formatAnalyte(r.analyte.value!, r.analyte.digits)} {r.analyte.unit}
                        </span>
                        <AbnormalFlag result={r.flag} />
                        <span className="text-xs text-muted-foreground">
                          基準 {refRangeText(r.analyte)}
                        </span>
                        <span className="ml-auto">
                          {acked ? (
                            <Badge variant="success" className="gap-1">
                              <IconCheck className="h-3.5 w-3.5" aria-hidden="true" />
                              報告記録済 ({NOW} 当直医)
                            </Badge>
                          ) : (
                            <Button
                              size="sm"
                              variant="destructive"
                              onClick={() => ackPanic(r.analyte.id)}
                            >
                              報告を記録
                            </Button>
                          )}
                        </span>
                      </li>
                    );
                  })}
                </ul>
                {!allPanicsAcked && (
                  <div className="mt-3">
                    <Button size="sm" variant="destructive" onClick={ackAllPanics}>
                      すべてのパニック値を報告記録
                    </Button>
                  </div>
                )}
              </AlertDescription>
            </Alert>
          </section>
        )}

        {/* polite status when all panics acknowledged */}
        {panicCount > 0 && allPanicsAcked && (
          <Alert variant="success" aria-live="polite">
            <IconCheck aria-hidden="true" />
            <AlertTitle as="h2">パニック値 {panicCount} 件すべて報告記録済み</AlertTitle>
            <AlertDescription>
              当直医へ報告済み（{NOW}）。結果確認（サインオフ）が可能になりました。
            </AlertDescription>
          </Alert>
        )}

        {/* ──────────────── Summary stats ──────────────── */}
        <section aria-labelledby="summary-heading">
          <h2 id="summary-heading" className="sr-only">
            検査結果サマリ
          </h2>
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
            <Statistic label="検査項目数" value={`${ALL_ROWS.length} 項目`} />
            <Statistic
              label="異常値 (H/L/異常)"
              value={`${abnormalCount} 件`}
              trend={abnormalCount > 0 ? "up" : "flat"}
              tone={abnormalCount > 0 ? "negative" : "neutral"}
              change={abnormalCount > 0 ? "要確認" : "なし"}
            />
            <Statistic
              label="パニック値"
              value={`${panicCount} 件`}
              tone={panicCount > 0 ? "negative" : "positive"}
              trend={panicCount > 0 ? "up" : "flat"}
              change={panicCount > 0 ? (allPanicsAcked ? "報告済" : "未報告") : "なし"}
            />
            <Statistic
              label="結果確認"
              value={signedOff ? "確認済" : "未確認"}
              tone={signedOff ? "positive" : "neutral"}
            />
          </div>
        </section>

        {/* ──────────────── Group nav / jump-to + per-group counts ──────────────── */}
        <nav aria-label="検査区分" className="flex flex-wrap gap-2">
          <GroupChip
            active={groupFilter === "all"}
            onClick={() => setGroupFilter("all")}
            label="すべて"
            count={ALL_ROWS.length}
            abnormal={abnormalCount}
          />
          {ANALYTE_GROUPS.map((g) => {
            const groupRows = ALL_ROWS.filter((r) => r.analyte.group === g.id);
            const ab = groupRows.filter((r) => r.flag.abnormal).length;
            return (
              <GroupChip
                key={g.id}
                active={groupFilter === g.id}
                onClick={() => setGroupFilter(g.id)}
                label={g.label}
                count={groupRows.length}
                abnormal={ab}
              />
            );
          })}
        </nav>

        {/* ──────────────── Results table (centerpiece) ──────────────── */}
        <Card>
          <CardHeader className="flex-row flex-wrap items-center justify-between gap-3">
            <div>
              <CardTitle as="h2">検査結果一覧</CardTitle>
              <CardDescription>
                結果値を基準値と照合。H=高値 / L=低値 / HH・LL=異常 / パニック=危険域。
              </CardDescription>
            </div>
            <Switch
              checked={abnormalOnly}
              onCheckedChange={setAbnormalOnly}
              label="異常値のみ表示"
              description={`基準外 ${abnormalCount} 件`}
            />
          </CardHeader>
          <CardContent className="px-2 sm:px-4">
            {visibleRows.length === 0 ? (
              <EmptyState
                title="該当する項目がありません"
                description={
                  abnormalOnly
                    ? "この区分に異常値はありません。フィルタを解除すると全項目を表示します。"
                    : "表示できる結果がありません。"
                }
              />
            ) : (
              <div className="space-y-6">
                {ANALYTE_GROUPS.filter((g) => rowsByGroup.has(g.id)).map((g) => (
                  <GroupTable
                    key={g.id}
                    groupLabel={g.label}
                    rows={rowsByGroup.get(g.id)!}
                    onPickTrend={setSelectedTrend}
                  />
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* ──────────────── Trend (推移) ──────────────── */}
        <Card>
          <CardHeader className="flex-row flex-wrap items-end justify-between gap-3">
            <div>
              <CardTitle as="h2">推移</CardTitle>
              <CardDescription>選択した項目の直近測定値の推移と基準線。</CardDescription>
            </div>
            <div className="w-full sm:w-64">
              <Select
                label="表示する項目"
                value={selectedTrend}
                onChange={(e) => setSelectedTrend(e.target.value)}
              >
                {ANALYTE_GROUPS.map((g) => (
                  <optgroup key={g.id} label={g.label}>
                    {ANALYTES.filter((a) => a.group === g.id).map((a) => (
                      <option key={a.id} value={a.id}>
                        {a.name}（{a.nameJa}）
                      </option>
                    ))}
                  </optgroup>
                ))}
              </Select>
            </div>
          </CardHeader>
          <CardContent>
            <AnalyteTrend analyte={trendAnalyte} />
          </CardContent>
        </Card>

        {/* ──────────────── Actions / sign-off ──────────────── */}
        <Card>
          <CardHeader>
            <CardTitle as="h2">結果確認・アクション</CardTitle>
            <CardDescription>
              パニック値を報告記録後に結果確認（サインオフ）が可能です。
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {!allPanicsAcked && (
              <Alert variant="warning" aria-live="polite">
                <IconAlertTriangleFilled aria-hidden="true" />
                <AlertTitle as="h3">サインオフできません</AlertTitle>
                <AlertDescription>
                  未報告のパニック値が {unackedPanics.length} 件あります。先に報告を記録してください。
                </AlertDescription>
              </Alert>
            )}
            {signedOff && (
              <Alert variant="success" aria-live="polite">
                <IconCheck aria-hidden="true" />
                <AlertTitle as="h3">結果確認 完了</AlertTitle>
                <AlertDescription>
                  当直医が {NOW} に結果を確認しました（電子署名）。
                </AlertDescription>
              </Alert>
            )}
            <div className="flex flex-wrap items-center gap-2">
              <Button
                variant="primary"
                disabled={!allPanicsAcked || signedOff}
                onClick={() => setSignedOff(true)}
                className="gap-1"
              >
                <IconStethoscope className="h-4 w-4" aria-hidden="true" />
                {signedOff ? "確認済み" : "結果を確認（サインオフ）"}
              </Button>
              <Button variant="outline" className="gap-1">
                <IconRefresh className="h-4 w-4" aria-hidden="true" />
                再検オーダー
              </Button>
              <Button
                variant="ghost"
                className="gap-1"
                onClick={() => typeof window !== "undefined" && window.print()}
              >
                <IconPrinter className="h-4 w-4" aria-hidden="true" />
                印刷 / PDF
              </Button>
            </div>
          </CardContent>
        </Card>
      </Container>
    </main>
  );
}

// ───────────────────────── sub-components ─────────────────────────

const PATIENT_FIELDS = {
  id: "PT-0098231",
  name: "佐藤 健一（68歳・男）",
  ward: "東4階病棟 / 412号",
  collectedAt: "2026-06-23 06:15",
  reportedAt: "2026-06-23 09:42",
  order: "LAB-20260623-014 / 血液・尿",
};

function ContextField({
  label,
  value,
  mono,
}: {
  label: string;
  value: string;
  mono?: boolean;
}) {
  return (
    <div>
      <dt className="text-xs font-medium text-muted-foreground">{label}</dt>
      <dd className={cn("mt-0.5 text-sm font-medium", mono && "tabular-nums")}>
        {value}
      </dd>
    </div>
  );
}

function GroupChip({
  active,
  onClick,
  label,
  count,
  abnormal,
}: {
  active: boolean;
  onClick: () => void;
  label: string;
  count: number;
  abnormal: number;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      aria-pressed={active}
      className={cn(
        "inline-flex items-center gap-1.5 rounded-full border px-3 py-1.5 text-sm font-medium transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-ring",
        active
          ? "border-foreground bg-foreground text-background"
          : "border-border bg-card text-foreground hover:bg-muted/60"
      )}
    >
      <span>{label}</span>
      <span className={cn("tabular-nums", active ? "opacity-80" : "text-muted-foreground")}>
        {count}
      </span>
      {abnormal > 0 && (
        <Badge variant="warning" className="h-4 px-1.5 py-0 text-[10px]">
          異常 {abnormal}
        </Badge>
      )}
    </button>
  );
}

function GroupTable({
  groupLabel,
  rows,
  onPickTrend,
}: {
  groupLabel: string;
  rows: Row[];
  onPickTrend: (id: string) => void;
}) {
  const headingId = `group-${groupLabel}`;
  return (
    <section aria-labelledby={headingId}>
      <h3 id={headingId} className="mb-2 px-1 text-sm font-semibold">
        {groupLabel}
        <span className="ml-2 font-normal text-muted-foreground">{rows.length} 項目</span>
      </h3>
      {/* Table is already wrapped in overflow-auto → horizontal scroll within card on 375px */}
      <Table striped className="min-w-[640px]">
        <TableHeader>
          <TableRow>
            <TableHead scope="col" className="min-w-[120px]">項目</TableHead>
            <TableHead scope="col" className="text-right">結果値</TableHead>
            <TableHead scope="col">単位</TableHead>
            <TableHead scope="col" className="whitespace-nowrap">基準値</TableHead>
            <TableHead scope="col">判定</TableHead>
            <TableHead scope="col" className="whitespace-nowrap">前回値 / 推移</TableHead>
            <TableHead scope="col"><span className="sr-only">推移を表示</span></TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {rows.map(({ analyte: a, flag }) => {
            const prev = previousValue(a);
            const delta = deltaFromPrevious(a);
            const rowTone =
              flag.tone === "destructive"
                ? "bg-destructive-subtle/40"
                : flag.tone === "warning"
                  ? "bg-warning-subtle/30"
                  : undefined;
            return (
              <TableRow key={a.id} className={rowTone}>
                <TableHead
                  scope="row"
                  className="bg-transparent text-left font-medium text-foreground"
                >
                  <span className="font-semibold">{a.name}</span>
                  <span className="block text-xs font-normal text-muted-foreground">
                    {a.nameJa}
                  </span>
                </TableHead>
                <TableCell className="text-right tabular-nums">
                  <span className={cn("font-semibold", flag.abnormal && "text-foreground")}>
                    {a.value != null ? formatAnalyte(a.value, a.digits) : "—"}
                  </span>
                </TableCell>
                <TableCell className="whitespace-nowrap text-xs text-muted-foreground">
                  {a.unit || "—"}
                </TableCell>
                <TableCell className="whitespace-nowrap text-xs tabular-nums text-muted-foreground">
                  {refRangeText(a)}
                </TableCell>
                <TableCell>
                  <AbnormalFlag result={flag} />
                </TableCell>
                <TableCell className="whitespace-nowrap text-xs tabular-nums">
                  {prev != null ? (
                    <span className="flex items-center gap-2">
                      <span className="text-muted-foreground">
                        {formatAnalyte(prev, a.digits)}
                      </span>
                      {delta != null && delta !== 0 ? (
                        <Delta
                          value={delta}
                          format={(v) => formatAnalyte(Math.abs(v), a.digits)}
                          // up/down isn't inherently good/bad on a lab value →
                          // neutral info tone, meaning carried by arrow + label.
                          tones={{ positive: "info", negative: "info", zero: "muted" }}
                          labels={{ positive: "前回比 増", negative: "前回比 減", zero: "変化なし" }}
                        />
                      ) : (
                        <span className="text-muted-foreground">±0</span>
                      )}
                    </span>
                  ) : (
                    <span className="text-muted-foreground">—</span>
                  )}
                </TableCell>
                <TableCell className="text-right">
                  <Button
                    size="sm"
                    variant="ghost"
                    onClick={() => onPickTrend(a.id)}
                    aria-label={`${a.name} の推移を表示`}
                    className="gap-1"
                  >
                    推移
                    <IconChevronDown className="h-3.5 w-3.5" aria-hidden="true" />
                  </Button>
                </TableCell>
              </TableRow>
            );
          })}
        </TableBody>
      </Table>
    </section>
  );
}
